import React from "react";

export default function BottomBar({ onHome, onWeathrie, onCommunity }) {
  return (
    <div className="rounded-2xl bg-black/60 backdrop-blur-md border border-white/10 shadow-xl px-4 py-2 flex items-center gap-6">
      <button
        onClick={onHome}
        className="px-3 py-2 text-white/90 hover:text-white hover:bg-white/10 rounded-xl transition"
      >
        Home
      </button>

      <button
        onClick={onWeathrie}
        className="px-3 py-2 text-white/90 hover:text-white hover:bg-white/10 rounded-xl transition"
      >
        onWeathrie
      </button>

      <button
        onClick={onCommunity}
        className="px-3 py-2 text-white/90 hover:text-white hover:bg-white/10 rounded-xl transition"
      >
        Community
      </button>
    </div>
  );
}
